[SysClientCacheDataMethodAttribute(true)]

public display PurchAgreementId agreementConfirmVer(PurchLine _this)
{
    PurchTable purchTable;

    select firstonly ETG_AgreementConfirmationVersion from purchTable
        where purchTable.PurchId == _this.PurchId;

    return purchTable.ETG_AgreementConfirmationVersion;

}

//NS, DLT ,6/03/2025  Invoice Numbers and status is updated  to Purchase agreement form  Release order lines

[SysClientCacheDataMethodAttribute(true)]

public display str getInvoiceId(PurchLine _this)
{
    VendInvoiceJour  vendInvoiceJour;
    str              invoicenumber;
    int              i = 1;

    while select InvoiceId from vendInvoiceJour where vendInvoiceJour.PurchId == _this.PurchId
    {
        if(i == 1 && vendInvoiceJour.InvoiceId)
        {
            invoicenumber = vendInvoiceJour.InvoiceId;
            i++;
        }
        else
        {
            invoicenumber = strFmt("%1,%2",invoicenumber, vendInvoiceJour.InvoiceId);
        }

    }
    return invoicenumber;
}
//NE, DLT ,6/03/2025  Invoice Numbers and status is updated  to Purchase agreement form  Release order lines.
